import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"01｜SSH 客户端与密钥","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/01-SSH客户端与密钥.md","filePath":"03.远程运维/01-SSH客户端与密钥.md","lastUpdated":null}'),n={name:"03.远程运维/01-SSH客户端与密钥.md"};function h(p,s,l,d,k,o){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="_01-ssh-客户端与密钥" tabindex="-1">01｜SSH 客户端与密钥 <a class="header-anchor" href="#_01-ssh-客户端与密钥" aria-label="Permalink to &quot;01｜SSH 客户端与密钥&quot;">​</a></h1><p>本地虚拟机里敲命令，机器就在面前。但真实的服务器在机房或云上，摸不到键盘。要把命令发过去、把结果拿回来，靠的是 SSH。</p><p>第一次连一台服务器，输完密码却发现一行红字警告&quot;主机指纹变了&quot;——连还是不连？密钥配好了却登录失败，提示&quot;permission denied&quot;——哪里错了？这些都和 SSH 的验证机制有关。本篇讲 SSH 客户端怎么连、怎么认证、怎么排错。</p><h2 id="一、连接的两层验证" tabindex="-1">一、连接的两层验证 <a class="header-anchor" href="#一、连接的两层验证" aria-label="Permalink to &quot;一、连接的两层验证&quot;">​</a></h2><p>每次 SSH 连接经历两重验证:</p><table tabindex="0"><thead><tr><th>层</th><th>验证什么</th><th>证据位置</th><th>类比</th></tr></thead><tbody><tr><td>服务器身份</td><td>这个 IP 是不是我以为的那台机器</td><td><code>~/.ssh/known_hosts</code></td><td>&quot;这栋楼是我要去的那栋&quot;</td></tr><tr><td>用户身份</td><td>我有没有权限登录</td><td>私钥或密码</td><td>&quot;我有这栋楼里某个房间的钥匙&quot;</td></tr></tbody></table><p><strong>楼对了但没钥匙进不去;有钥匙但找错了楼更危险</strong>——你以为连的是自己的服务器,实际上是攻击者架的钓鱼机。</p><h3 id="最基本用法" tabindex="-1">最基本用法 <a class="header-anchor" href="#最基本用法" aria-label="Permalink to &quot;最基本用法&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 交互式登录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;hostname -I&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 执行单条命令</span></span></code></pre></div><h3 id="脚本中判断连接与命令" tabindex="-1">脚本中判断连接与命令 <a class="header-anchor" href="#脚本中判断连接与命令" aria-label="Permalink to &quot;脚本中判断连接与命令&quot;">​</a></h3><p>脚本里跑 SSH 时需要区分&quot;连接不通&quot;和&quot;远端命令失败&quot;:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设 ConnectTimeout=5,否则网络不可达时默认等几十秒</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ConnectTimeout=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;systemctl is-active --quiet nginx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;nginx active&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;SSH failed or nginx inactive&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&amp;2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p><code>ConnectTimeout=5</code> 是 TCP 连接阶段的超时,<strong>不是命令执行超时</strong>。脚本里不设超时,一台连不上的机器就能卡住整个批量任务。</p><h2 id="二、known-hosts-与主机指纹验证" tabindex="-1">二、known_hosts 与主机指纹验证 <a class="header-anchor" href="#二、known-hosts-与主机指纹验证" aria-label="Permalink to &quot;二、known_hosts 与主机指纹验证&quot;">​</a></h2><p>第一次连一台新机器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>屏幕不是直接要密码，而是先问一句：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>The authenticity of host &#39;192.168.10.129&#39; can&#39;t be established.</span></span>
<span class="line"><span>ED25519 key fingerprint is SHA256:xxxx...</span></span>
<span class="line"><span>Are you sure you want to continue connecting (yes/no/[fingerprint])?</span></span></code></pre></div><p>这是 SSH 在问：你确定这台机器是你要连的那台吗？它报出一串指纹（机器公钥的摘要），让你确认。输入 <code>yes</code>，这个指纹存进 <code>~/.ssh/known_hosts</code>，下次再连就不问了——直接比对指纹，对得上才放行。</p><p>为什么要这一步？防止连错机器。比如你以为连的是自己的服务器，实际 DNS 被劫持、IP 复用，连到了攻击者架的钓鱼机上。指纹对不上，SSH 会拦下来。</p><h3 id="主机密钥变了怎么办" tabindex="-1">主机密钥变了怎么办 <a class="header-anchor" href="#主机密钥变了怎么办" aria-label="Permalink to &quot;主机密钥变了怎么办&quot;">​</a></h3><p>某天再连这台机器，突然冒出一堆红字：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@</span></span>
<span class="line"><span>@ WARNING: REMOTE HOST IDENTIFICATION HAS CHANGED! @</span></span>
<span class="line"><span>@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@@</span></span></code></pre></div><p>意思是：这台机器的指纹，和 known_hosts 里记的对不上了。两种可能：合法的（重装系统、重建云机、换了 IP 复用），或不合法的（真被劫持了）。</p><p>确认是合法变化后（比如刚重装过），删掉旧记录，让它重新认证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span></span></code></pre></div><p>下次再连，又回到第一次连接那个&quot;确认&quot;的流程。</p><h3 id="自动化里别图省事关掉校验" tabindex="-1">自动化里别图省事关掉校验 <a class="header-anchor" href="#自动化里别图省事关掉校验" aria-label="Permalink to &quot;自动化里别图省事关掉校验&quot;">​</a></h3><p>写脚本批量连机器时，那个&quot;yes/no&quot;提示很烦人。有人图省事加 <code>-o StrictHostKeyChecking=no</code> 跳过校验——这等于把指纹校验关了，钓鱼机也能连上。临时测试可以，生产脚本长期这么用很危险。</p><p>可靠做法是提前把指纹写进 known_hosts，而不是现场信任。装机流程里把每台机器的指纹记下来，脚本用已知的指纹。<code>ssh-keyscan</code> 能拿到对方报的公钥，但注意它不验证真伪——对方报什么就存什么，所以得在可信网络里跑，不能从不可信来源拿指纹。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keyscan</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/known_hosts</span></span></code></pre></div><h2 id="三、密钥认证" tabindex="-1">三、密钥认证 <a class="header-anchor" href="#三、密钥认证" aria-label="Permalink to &quot;三、密钥认证&quot;">​</a></h2><p>密码登录有个麻烦：每次输密码，脚本里没法自动化；密码弱了容易被爆破；人多时密码谁都知道、改了要通知所有人。密钥认证解决这些——用一对密钥代替密码，私钥留本机、公钥放服务器，登录时自动验证，不用输密码。</p><h3 id="生成密钥对" tabindex="-1">生成密钥对 <a class="header-anchor" href="#生成密钥对" aria-label="Permalink to &quot;生成密钥对&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 700</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ops@workstation-01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span></span></code></pre></div><table tabindex="0"><thead><tr><th>参数</th><th>含义</th></tr></thead><tbody><tr><td><code>-t ed25519</code></td><td>Ed25519 算法，比 RSA 更短、更快、安全</td></tr><tr><td><code>-a 100</code></td><td>私钥口令的迭代轮次，防暴力破解</td></tr><tr><td><code>-C</code></td><td>公钥注释，多把密钥时便于识别</td></tr><tr><td><code>-f</code></td><td>输出路径，避免覆盖默认密钥</td></tr></tbody></table><p>生成时会问要不要给私钥设口令（passphrase）。设了的话，每次用密钥得输一次口令——更安全，私钥文件泄露了没口令也用不了。嫌麻烦可以用 ssh-agent 免重复输入（后面讲）。</p><p>生成后两个文件，权限要紧：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.ssh/id_ed25519_ops          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 600（私钥，仅自己可读写，泄露=密码泄露）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.ssh/id_ed25519_ops.pub      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 644（公钥，可公开）</span></span></code></pre></div><h3 id="公钥传到目标服务器" tabindex="-1">公钥传到目标服务器 <a class="header-anchor" href="#公钥传到目标服务器" aria-label="Permalink to &quot;公钥传到目标服务器&quot;">​</a></h3><p>光在本机有密钥不行，得把公钥放到服务器上，服务器才认：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-copy-id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops.pub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p><code>ssh-copy-id</code> 把本地公钥追加到远程的 <code>~/.ssh/authorized_keys</code>。没有该命令时手动操作：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops.pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    umask 077</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mkdir -p ~/.ssh</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    cat &gt;&gt; ~/.ssh/authorized_keys</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre></div><p><code>umask 077</code> 保证新建的目录和文件权限收紧——服务端权限检查严格，过宽会拒绝使用。</p><h3 id="ssh-agent-免输-passphrase" tabindex="-1">ssh-agent：免输 passphrase <a class="header-anchor" href="#ssh-agent-免输-passphrase" aria-label="Permalink to &quot;ssh-agent：免输 passphrase&quot;">​</a></h3><p>前面给私钥设了口令，每次登录都得输一次。连十几台机器输十几遍，烦。ssh-agent 解决这个——启动一次 agent，把私钥加载进去，输一次口令，之后这个会话里所有 ssh 自动用 agent 里的密钥，不再问口令。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 启动 agent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 输一次口令，后续免密</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           # 查看 agent 中已加载的密钥</span></span></code></pre></div><p><code>eval &quot;$(...)&quot;</code> 是因为 ssh-agent 启动时要设几个环境变量，它输出的不是密钥而是 <code>export SSH_AUTH_SOCK=...</code> 之类的语句，<code>eval</code> 执行这些语句让当前 shell 能找到 agent。</p><h3 id="sshd-权限要求" tabindex="-1">sshd 权限要求 <a class="header-anchor" href="#sshd-权限要求" aria-label="Permalink to &quot;sshd 权限要求&quot;">​</a></h3><p>密钥明明配对了，却提示&quot;Permission denied&quot;——多半是权限问题。sshd 对 <code>.ssh</code> 相关目录和文件的权限检查很严格，过宽就拒绝认证（防止别人偷偷改了你的 authorized_keys）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.ssh                      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 700（不能同组/其他可写）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.ssh/authorized_keys      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 600</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">私钥文件</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 600</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">家目录</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # 不能对组/其他人可写</span></span></code></pre></div><p>家目录这行容易被忽略——家目录对组可写，sshd 也不认。密钥对了但认证失败，先查权限和 SELinux：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ld</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/authorized_keys</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 看权限对不对</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restorecon</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Rv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # SELinux 上下文恢复（RHEL 系）</span></span></code></pre></div><h2 id="四、-ssh-config" tabindex="-1">四、~/.ssh/config <a class="header-anchor" href="#四、-ssh-config" aria-label="Permalink to &quot;四、~/.ssh/config&quot;">​</a></h2><p>连一台机器要敲 <code>ssh -i ~/.ssh/id_ed25519_ops -p 2222 ops@192.168.10.129</code>——长、难记、易错。机器多了更烦。</p><p>ssh config 把这些参数存起来，给每台机器起个别名：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ~/.ssh/config</span></span>
<span class="line"><span>Host test-rocky</span></span>
<span class="line"><span>    HostName 192.168.10.129</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    Port 22</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_ops</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span>    ServerAliveInterval 30</span></span>
<span class="line"><span>    ServerAliveCountMax 3</span></span></code></pre></div><p>之后直接 <code>ssh test-rocky</code>，所有参数自动带上。</p><p>几个常用字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>Host</code></td><td>本地别名（支持通配符）</td></tr><tr><td><code>HostName</code></td><td>真实地址</td></tr><tr><td><code>IdentityFile</code></td><td>指定私钥</td></tr><tr><td><code>IdentitiesOnly yes</code></td><td>只试配置中的私钥，不逐个试 agent 中的</td></tr><tr><td><code>ServerAliveInterval</code></td><td>客户端心跳间隔，防空闲连接被中间设备断开</td></tr></tbody></table><h3 id="按环境隔离私钥" tabindex="-1">按环境隔离私钥 <a class="header-anchor" href="#按环境隔离私钥" aria-label="Permalink to &quot;按环境隔离私钥&quot;">​</a></h3><p>生产、测试用不同密钥，至少让测试环境密钥泄露不影响生产。用通配符批量配：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host prod-*</span></span>
<span class="line"><span>    User ops</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_prod</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Host test-*</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_test</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span></code></pre></div><p><code>Host prod-*</code> 匹配所有以 <code>prod-</code> 开头的别名，<code>ssh prod-web-01</code> 自动用生产密钥。</p><h3 id="排查配置的最终值" tabindex="-1">排查配置的最终值 <a class="header-anchor" href="#排查配置的最终值" aria-label="Permalink to &quot;排查配置的最终值&quot;">​</a></h3><p>配了一堆，不知道实际生效的是哪个。<code>-G</code> 显示合并所有配置后的最终值：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-rocky</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> identityfile</span></span></code></pre></div><p>排查&quot;为什么用了错的 key&quot;时特别实用——能看到 SSH 实际拿的是哪把私钥。</p><h2 id="五、proxyjump-跳板访问" tabindex="-1">五、ProxyJump 跳板访问 <a class="header-anchor" href="#五、proxyjump-跳板访问" aria-label="Permalink to &quot;五、ProxyJump 跳板访问&quot;">​</a></h2><p>生产服务器经常没有公网 IP，只有一台跳板机暴露在公网。要连内部机器，得先到跳板，再从跳板连进去。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># OpenSSH 7.3+ 一条命令搞定</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -J</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@203.0.113.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@10.10.1.21</span></span></code></pre></div><h3 id="config-写法" tabindex="-1">config 写法 <a class="header-anchor" href="#config-写法" aria-label="Permalink to &quot;config 写法&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host jump</span></span>
<span class="line"><span>    HostName 203.0.113.10</span></span>
<span class="line"><span>    User ops</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_jump</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Host app-01</span></span>
<span class="line"><span>    HostName 10.10.1.21</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    ProxyJump jump</span></span></code></pre></div><p>之后直接 <code>ssh app-01</code>。</p><h3 id="多跳板" tabindex="-1">多跳板 <a class="header-anchor" href="#多跳板" aria-label="Permalink to &quot;多跳板&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -J</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@jump1,user@jump2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> target</span></span></code></pre></div><p>链路：本地 → jump1 → jump2 → target。</p><h2 id="六、ssh-端口转发" tabindex="-1">六、SSH 端口转发 <a class="header-anchor" href="#六、ssh-端口转发" aria-label="Permalink to &quot;六、SSH 端口转发&quot;">​</a></h2><p>一台数据库在内网 <code>10.10.2.15:5432</code>，本机直连：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.10.2.15</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span></span></code></pre></div><p>连不上——超时，因为本机不在那个内网里。但有一台跳板机 <code>db-gateway</code>，它在内网里，能连到那台数据库。</p><p>SSH 端口转发解决这个：让本机的某个端口，通过 SSH 隧道连到跳板机，再由跳板机去访问内网资源。本机连本地端口，等于在连内网。</p><h3 id="本地转发-l-访问远端能访问的资源" tabindex="-1">本地转发 -L：访问远端能访问的资源 <a class="header-anchor" href="#本地转发-l-访问远端能访问的资源" aria-label="Permalink to &quot;本地转发 -L：访问远端能访问的资源&quot;">​</a></h3><p>先连最简单的情况——数据库就在跳板机本机（<code>127.0.0.1:5432</code>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:127.0.0.1:5432</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@db-gateway</span></span></code></pre></div><p>这条命令连上后不退（<code>-N</code> 表示不执行远端命令，只建隧道），本机 15432 端口被占住。另开一个终端：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 127.0.0.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 15432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span></span></code></pre></div><p>连上了。本机 15432 的流量，经 SSH 隧道到 db-gateway，再由 db-gateway 访问它自己的 5432。</p><p>这里有个关键认知容易踩错：<code>127.0.0.1:5432</code> 这个地址，是<strong>从 db-gateway 机器的视角</strong>解析的，不是从本机。所以&quot;访问谁&quot;要站在跳板机那边想。</p><p>数据库不在跳板机本机、而在内网另一台 <code>10.10.2.15</code> 时，改转发目标：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:10.10.2.15:5432</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@db-gateway</span></span></code></pre></div><p>db-gateway 能访问 10.10.2.15，所以这个能通。如果把 <code>10.10.2.15</code> 写成本机视角的地址就错了——本机访问不到 10.10.2.15，得让跳板机去访问。</p><p>加上一个安全选项：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:10.10.2.15:5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ExitOnForwardFailure=yes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@db-gateway</span></span></code></pre></div><p><code>ExitOnForwardFailure=yes</code> 在端口绑定失败时让 SSH 直接退出。否则绑定失败的 SSH 会在后台静默跑着，你以为端口通了，其实没绑上。</p><h3 id="远程转发-r-把本机的端口暴露到远端" tabindex="-1">远程转发 -R：把本机的端口暴露到远端 <a class="header-anchor" href="#远程转发-r-把本机的端口暴露到远端" aria-label="Permalink to &quot;远程转发 -R：把本机的端口暴露到远端&quot;">​</a></h3><p>反过来——本机起了个开发服务（8080），想让外部同事临时看一眼，但本机没公网 IP。借一台公网 VPS：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18080:127.0.0.1:8080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@public-gateway</span></span></code></pre></div><p>效果：在 public-gateway 上访问 <code>127.0.0.1:18080</code>，流量经隧道回到本机 8080。同事连 VPS 的 18080 就看到了本机的开发服务。</p><h3 id="动态转发-d-socks-代理" tabindex="-1">动态转发 -D：SOCKS 代理 <a class="header-anchor" href="#动态转发-d-socks-代理" aria-label="Permalink to &quot;动态转发 -D：SOCKS 代理&quot;">​</a></h3><p>前面两种是转发一个固定端口。如果想&quot;通过跳板机访问内网任意地址&quot;，用动态转发，相当于建了个 SOCKS 代理：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 127.0.0.1:1080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@gateway</span></span></code></pre></div><p>本机 1080 成了 SOCKS5 代理，浏览器或 curl 配上它，请求都经 gateway 转发：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --socks5-hostname</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 127.0.0.1:1080</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://内网域名</span></span></code></pre></div><p><code>--socks5-hostname</code> 把域名解析也交给代理端——内网域名在公网 DNS 解析不了，让 gateway 那边解析才有用。</p><h3 id="后台运行转发" tabindex="-1">后台运行转发 <a class="header-anchor" href="#后台运行转发" aria-label="Permalink to &quot;后台运行转发&quot;">​</a></h3><p>前面的命令连上后不退，占着一个终端。加 <code>-f</code> 让它认证成功后进后台：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15432:10.10.2.15:5432</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ExitOnForwardFailure=yes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@db-gateway</span></span></code></pre></div><p><code>-f</code> 进后台后，终端还能干别的。但要注意：这种后台转发生命周期不好管，关掉要 <code>ps</code> 找进程 kill，或配 ControlMaster（下一节）统一管。</p><h2 id="七、controlmaster-连接复用" tabindex="-1">七、ControlMaster：连接复用 <a class="header-anchor" href="#七、controlmaster-连接复用" aria-label="Permalink to &quot;七、ControlMaster：连接复用&quot;">​</a></h2><p>对同一台机器，一会儿 <code>ssh</code> 执行命令、一会儿 <code>scp</code> 传文件、一会儿又 <code>ssh</code> 一下——每次都重新握手、认证一遍。机器多、操作频繁时，这开销积累起来明显。</p><p>ControlMaster 让多次连同一台机器时复用第一条连接——握手认证只做一次，后续连接共用这条通道。在 ssh config 里配：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host *</span></span>
<span class="line"><span>    ControlMaster auto</span></span>
<span class="line"><span>    ControlPath ~/.ssh/controlmasters/%r@%h:%p</span></span>
<span class="line"><span>    ControlPersist 10m</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/controlmasters</span></span></code></pre></div><p><code>ControlMaster auto</code> 自动复用、<code>ControlPath</code> 指定 socket 文件位置、<code>ControlPersist 10m</code> 让连接在最后一次使用后还保持 10 分钟（这段时间内再连直接复用，不用重新认证）。</p><p>管理复用连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 看连接状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 主动关闭主连接</span></span></code></pre></div><h2 id="八、连接排错" tabindex="-1">八、连接排错 <a class="header-anchor" href="#八、连接排错" aria-label="Permalink to &quot;八、连接排错&quot;">​</a></h2><p>ssh 连不上，可能卡在好几处：网络不通、端口没开、认证失败、权限不对。光看一句&quot;Permission denied&quot;分不清是哪一类。SSH 自己有详细日志，让它说出来。</p><h3 id="客户端日志" tabindex="-1">客户端日志 <a class="header-anchor" href="#客户端日志" aria-label="Permalink to &quot;客户端日志&quot;">​</a></h3><p>加 <code>-v</code>（一个 v 信息少，三个最详细）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vvv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>输出里几个关键字，对应不同问题：</p><table tabindex="0"><thead><tr><th>日志内容</th><th>含义</th></tr></thead><tbody><tr><td><code>Connection timed out</code></td><td>网络不通，到不了那台机器</td></tr><tr><td><code>Connection refused</code></td><td>网络通了，但端口没监听或被防火墙拒</td></tr><tr><td><code>Offering public key</code></td><td>正在尝试某把公钥</td></tr><tr><td><code>Authentications that can continue</code></td><td>服务端允许的认证方式</td></tr><tr><td><code>Permission denied</code></td><td>认证失败（key 不对、用户不对、权限不对）</td></tr></tbody></table><p><code>timed out</code> 和 <code>refused</code> 是网络层问题，<code>Permission denied</code> 是认证层问题，分开排查。</p><h3 id="只测试密钥认证" tabindex="-1">只测试密钥认证 <a class="header-anchor" href="#只测试密钥认证" aria-label="Permalink to &quot;只测试密钥认证&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PreferredAuthentications=publickey</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PasswordAuthentication=no</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    root@192.168.10.129</span></span></code></pre></div><p>确认登录成功是密钥真正生效,而非密码兜底。</p><h3 id="服务端日志" tabindex="-1">服务端日志 <a class="header-anchor" href="#服务端日志" aria-label="Permalink to &quot;服务端日志&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # systemd 环境</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/secure</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/auth.log</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # Debian 系</span></span></code></pre></div><h3 id="改配置的安全习惯" tabindex="-1">改配置的安全习惯 <a class="header-anchor" href="#改配置的安全习惯" aria-label="Permalink to &quot;改配置的安全习惯&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># reload 不中断现有连接</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span></span></code></pre></div><p><strong>保留一个已登录的窗口不要关,另开终端验证新配置能登录后再关旧窗口</strong>——这条习惯能避免无数次&quot;把自己关在外面&quot;的事故。</p>`,134)])])}const g=a(n,[["render",h]]);export{c as __pageData,g as default};
